		--SELECT @ACLUserID = UserId, @UserGUID = @UserGUID, @CreatedAccessId = AL.UpdateAccessId  FROM [GEN].fxGetAccessLevel('DELETE','RSU','UserRecruitPolicyAndProcedures') AS AL WHERE (AL.UpdateAccessId > 0)

